INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Hello thank you for running the test with us. It is much appreciated!', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:33:34.893091+00:00', '4068127f-c5ac-45ed-87cd-9caeba704088', 'text', NULL, '2026-04-21T06:37:03.41+00:00', '50189915-d328-46b2-84d5-28fb750405c9') ON CONFLICT DO NOTHING;
INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Hi, thanks very much for sending your quote through.  Just to confirm, this is a BookATrade test job created so we can test the full customer and provider flow properly. No real work will be going ahead from this job.  That said, we’d still love to go through the process as naturally as possible to see how quoting, messaging, and the overall user experience feels on both sides.  So please treat this as a test run of a real enquiry. We may reply, ask a couple of follow-up questions, and move through the next stages just to make sure everything works as it should.  Thanks again for helping us test BookATrade, it’s genuinely appreciated.', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:36:08.765402+00:00', 'b9aee2a6-24a0-4e1b-b246-bb4c0d01cc36', 'text', NULL, '2026-04-21T06:37:03.41+00:00', '50189915-d328-46b2-84d5-28fb750405c9') ON CONFLICT DO NOTHING;
INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Why a pre-paint finish only quote, sorry?', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:37:25.644354+00:00', '77a3f26e-0ce1-494b-b5e5-57a7fa2130a6', 'text', NULL, '2026-04-21T06:37:26.169+00:00', '50189915-d328-46b2-84d5-28fb750405c9') ON CONFLICT DO NOTHING;
INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('So we do not offer painting services as it’s not something we are trained or specialise in. We would complete sanding, but a painter / decorator would the be required to prime and paint the cabinet. Depending on the materials used, some finer sanding may be required ahead of priming and painting.', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:38:58.231536+00:00', '437bfe59-9665-4883-a543-9ea4db026ee1', 'text', NULL, '2026-04-21T06:39:25.359+00:00', '0a5385cf-bf19-4162-93e9-8f623d456c70') ON CONFLICT DO NOTHING;
INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Hello, installation of a bathroom door would be £120. If you would like to advise which style of door, and colour handles, lock & hinges you would like, I can also provide a price to supply & fit.', '45f66dc3-acfd-4ff3-8ae2-0f127c7a7bc4', '2026-04-21T06:42:27.602055+00:00', '20b06b1c-ecf1-40e8-9c35-c047e555b01f', 'text', NULL, NULL, '0a5385cf-bf19-4162-93e9-8f623d456c70') ON CONFLICT DO NOTHING;
INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Alternatively clients choose to paint it themselves, so we would advise them of the same information at the point of quoting', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:39:26.452037+00:00', '572fcd7b-8ae3-403d-bc6b-b5e621584786', 'text', NULL, '2026-04-21T06:39:26.052+00:00', '0a5385cf-bf19-4162-93e9-8f623d456c70') ON CONFLICT DO NOTHING;
