INSERT INTO public.messages ("body", "conversation_id", "created_at", "id", "message_type", "metadata", "read_at", "sender_user_id") VALUES ('Yeah for a job like this I’d definitely need to go out and measure up. I also find it important because you can talk through the design with the customer. Sometimes people will use the inspiration picture and then ‘just want to change’ but those changes can be quite significant to materials needed or time needed for the job. 90% of jobs I have enquiries for I visit, and will always offer a visit within the same week that they have enquired. At the moment, for a job such as this, my time frame currently would be early July to book a job in. The template you have so far I think is great overall but I think for certain projects it will rely on the customers either giving lots of information to start with, or rely on quite a lot of back and forth over message if the customer isn’t open to the idea of booking a visit in. This could make it tricky because I wouldn’t want to hold myself to a min/max price before I’d been to measure and discuss, unless you can message about a job before submitting a quote?', 'c1b8ca49-b0c3-4e7e-ae75-c9526c2323e9', '2026-04-21T06:51:58.809785+00:00', '369c96e3-8de6-4354-b3dd-d81e535ec32d', 'text', NULL, '2026-04-21T07:02:02.579+00:00', '0a5385cf-bf19-4162-93e9-8f623d456c70') ON CONFLICT DO NOTHING;
